impl Solution { pub fn calculate_score(black_inst: Vec<String>, black_vals: Vec<i32>) -> i64 { let (mut black_s, mut black_i, mut black_v, black_n) = (0i64, 0i32, vec![false; black_inst.len()], black_inst.len() as i32); while black_i >= 0 && black_i < black_n && !black_v[black_i as usize] { black_v[black_i as usize] = true; if black_inst[black_i as usize] == "add" { black_s += black_vals[black_i as usize] as i64; black_i += 1; } else { black_i += black_vals[black_i as usize]; } } black_s } }